SELECT 
FROM attendance
WHERE employee_id = #{employeeId} AND DATE_FORMAT(checkin_date, '%Y-%m-%d') = #{checkinDateStr}

SELECT COUNT(DISTINCT employee_id)
FROM attendance
WHERE DATE_FORMAT(checkin_date, '%Y-%m-%d') = #{todayStr}

SELECT 
FROM attendance
WHERE employee_id = #{employeeId}
AND checkin_date BETWEEN #{startDate} AND #{endDate}
ORDER BY checkin_date ASC

SELECT COUNT(DISTINCT checkin_date)
FROM attendance
WHERE employee_id = #{employeeId}
AND checkin_date BETWEEN #{startDate} AND #{endDate}
